\n  bottom: 30px;\n  width: 3px;\n  background: linear-gradient(to bottom, var(--primary-gold), var(--primary-gold-dark));\n}\n\n.process-step[_ngcontent-%COMP%] {\n  display: flex;\n  gap: 30px;\n  margin-bottom: 50px;\n  position: relative;\n}\n.process-step[_ngcontent-%COMP%]:last-child {\n  margin-bottom: 0;\n}\n.process-step[_ngcontent-%COMP%]   .step-number[_ngcontent-%COMP%] {\n  flex-shrink: 0;\n  width: 60px;\n  height: 60px;\n  background: var(--primary-gold);\n  color: white;\n  border-radius: 50%;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  font-size: 1.5rem;\n  font-weight: 900;\n  box-shadow: 0 5px 15px rgba(144, 194, 227, 0.4);\n  position: relative;\n  z-index: 1;\n}\n.process-step[_ngcontent-%COMP%]   .step-content[_ngcontent-%COMP%] {\n  flex: 1;\n  background: white;\n  padding: 25px 30px;\n  border-radius: 15px;\n  box-shadow: var(--shadow-sm);\n  border-left: 4px solid var(--primary-gold);\n}\n.process-step[_ngcontent-%COMP%]   .step-content[_ngcontent-%COMP%]   h3[_ngcontent-%COMP%] {\n  font-size: 1.5rem;\n  color: var(--dark-primary);\n  margin-bottom: 10px;\n  font-weight: 800;\n}\n.process-step[_ngcontent-%COMP%]   .step-content[_ngcontent-%COMP%]   p[_ngcontent-%COMP%] {\n  color: var(--text-muted);\n  margin-bottom: 15px;\n  line-height: 1.6;\n}\n.process-step[_ngcontent-%COMP%]   .step-content[_ngcontent-%COMP%]   .step-duration[_ngcontent-%COMP%] {\n  display: inline-block;\n  padding: 6px 15px;\n  background: rgba(229, 198, 67, 0.15);\n  border-radius: 20px;\n  font-size: 0.9rem;\n  color: var(--primary-gold-dark);\n  font-weight: 700;\n}\n\n\n\n.zones-grid[_ngcontent-%COMP%] {\n  display: grid;\n  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));\n  gap: 25px;\n  margin-bottom: 40px;\n}\n\n.zone-card[_ngcontent-%COMP%] {\n  background: white;\n  padding: 25px;\n  border-radius: 15px;\n  box-shadow: var(--shadow-sm);\n  transition: var(--transition-normal);\n  border: 2px solid transparent;\n}\n.